UPDATE TBL_PAYMENT
   SET STATUS = #{nextStatus},
       UPDATED_AT = SYSDATE
 WHERE ORDER_ID = #{orderId}
   AND STATUS = #{currentStatus}

mapper.select:
SELECT POINT_WALLET_ID
FROM TBL_POINT_WALLET
WHERE FK_MEMBERID = #{memberId}

SELECT NVL(AVAILABLE_BALANCE, 0)
FROM TBL_POINT_WALLET
WHERE FK_MEMBERID = #{memberId}

SELECT COUNT(*)
FROM TBL_PAYMENT
WHERE FK_MEMBERID = #{memberId}

mapper.update:
UPDATE TBL_POINT_WALLET
SET AVAILABLE_BALANCE = AVAILABLE_BALANCE - #{amount},
    UPDATED_AT = SYSDATE
WHERE FK_MEMBERID = #{memberId}
  AND AVAILABLE_BALANCE >= #{amount}
